val dprFiles = DprFiles(System.getProperty("user.home"))

fun getFileOrURL(fileOrUrl: String): String? {
    return if (fileOrUrl.startsWith("http")) {
        var body = ""
        runBlocking {
            body = CharacterAPI.getRequest(fileOrUrl)
        }
        body
    }
    else {
        File(fileOrUrl).readText()
    }
}

fun getCharacter(arg: String): com.vikinghelmet.dnd.dpr.character.Character? {
    var character: com.vikinghelmet.dnd.dpr.character.Character? = null
    runBlocking {
        character = CharacterAPI.getRemoteCharacterByUrl (getCharacterApiURL (arg)).second
    }
    return character
}


fun getEditableCharacter(json: String): EditableCharacter? {
    if (json.isEmpty()) return null
    val editableFields: EditableFields = Json.Default.decodeFromString(json)

    val baseline = getCharacter(editableFields.remoteId.toString()) ?: return null
    return EditableCharacter(baseline, editableFields)
}

fun getResource(fileName: String): String? {
    val inputStream: InputStream = object {}.javaClass.getResourceAsStream("/$fileName") ?: return null
    try {
        return inputStream.bufferedReader().use { it.readText() }
    } catch (e: Exception) {
        e.printStackTrace()
        return null
    }
}

fun getProperties(fileName: String): java.util.Properties {
    val properties = Properties()
    val inputStream = object {}.javaClass.getResourceAsStream("/$fileName") ?: return properties
    inputStream.use { properties.load(it) }
    return properties
}

fun showResults(resultList: List<ScenarioResult>) {

    val sortedResults = ScenarioResult.topResults(resultList, Constants.SCENARIO_OUTPUT_MAX)

    // result summaries, prefixed with "#"
    val buf = StringBuilder()
    sortedResults.forEach {
        buf.append("# ")
            .append(Globals.getPercent(it.totalDPR))
            .append(" \t")
            .append(it.scenario.getLabel())
            .append("\n")
    }
    println(buf.toString())

    // full results
    sortedResults.forEach {
        println(it.output())
    }
}

fun runScenarios(character: Character, args : Array<String>, i: Int): List<ScenarioResult> {
    val monster = Globals.getMonster(args[i+1])
    val builder = ScenarioBuilder(character,monster)

    fun optionalArg(index: Int, default: Int) = if (index < args.size) args[index].toInt() else default

    val iterator = ScenarioIterator (builder.build (args[i+2].toInt(),
        optionalArg (i+3, NUM_TURNS_PER_SCENARIO),
        optionalArg (i+4, DEFAULT_NUM_TARGETS),
        optionalArg (i+5, DEFAULT_TARGET_RADIUS)))

    val resultList: MutableList<ScenarioResult> = mutableListOf()
    iterator.forEach { resultList.add(ScenarioCalculator(it).calculateDPRForAllTurns()) }
    return resultList
}

fun showUsage() {
    println("""
Usage:  [-d] [--csv] [+feat=name] [+aaa=N]  [file.json ...]  [character]  < dump[:opt] | search<opt> | <attacks> >

Options:

    -d              debug logging
    --csv           CSV output
    
    --maxTurns=N    number of turns per scenario (default = 5)
    --maxResults=N  number of results in final output (default = 30), sorted by totalDamage (see -z below)
    
    +feat=name      add feat
    +aaa=N          increase ability (3-letter shorthand = str, dex, ...) by N = [1-9]

File:

     file.json   load spell or monster data; this is optional: program contains most 2014 and 2024 data

Character:

     NumericID   read character from DND Beyond API (character must have public visibility)
     file.json   read character from a local file

Dump:

     dump:spells     export all known spells
     dump:monsters   export all known monsters
     dump:attacks    export attacks from user input
     dump:character  export (minimal) character data from DND Beyond
     dump:features   export supported features: racialTraits, actionModifiers, feats
     dump            export all of the above

Search:

     search:NAME     search for NAME in list of spells/monsters, and display details if found

Attacks:

     -a  <monster> <turn[;turn...] >   one/more turns, each a comma-separated list of spell or weapon name
     
     -z  <monster> <proximityInFeet>  [numTurns (${NUM_TURNS_PER_SCENARIO})]  [numTargets (${DEFAULT_NUM_TARGETS})]  [targetRadius (${DEFAULT_TARGET_RADIUS})]

     -p  <level>  <monster> <proximityInFeet>  [numTurns (${NUM_TURNS_PER_SCENARIO})]  [numTargets (${DEFAULT_NUM_TARGETS})]  [targetRadius (${DEFAULT_TARGET_RADIUS})]
  
  
Note: '-a' and '-z' operate on a single character.  The '-p' option iterates over an entire party, from ~/.dpr/character/editable, and calculates results at the specified character level 

""")
}

fun main(args : Array<String>) {
    JulConfigurator()

    var exitEarly = false
    var character: com.vikinghelmet.dnd.dpr.character.Character? = null
    val turns = ArrayList<Turn>()

    if (args.isEmpty()) {
        showUsage()
        System.exit(0)
    }

    /*
Level	Priority	Usage
VERBOSE	0	Most detailed
DEBUG	1	Debugging information
INFO	2	General informational messages
WARN	3	Warning messages for potential issues
ERROR	4	Error messages for failures
FATAL	5	Critical errors (flushes sinks and crashes)
OFF	6	Disables all logging
     */
    Globals.initLogger(if (args.contains("-v")) LogLevel.VERBOSE
                else if (args.contains("-d")) LogLevel.DEBUG
                else if (args.contains("-i")) LogLevel.INFO
                else LogLevel.WARN)

    val logger = LoggerFactory.get(DprCmd::class.simpleName ?: "no simpleName")   // DprCmd
    //val logger = LoggerFactory.get(DprCmd::class.qualifiedName ?: "no qualifiedName") // com.vikinghelmet.dnd.dpr.DprCmd

    logger.warn { "logging initialized" }

    for (filename in mutableListOf("spells.json","extra.spells.json")) {
        Globals.addSpells(getResource(filename) ?: "[]")
    }

    Globals.addSubclassSpellsPrepared(getResource("subclass.spellprep.json") ?: "[]")

    Globals.addMonsters(getResource("monsters.json") ?: "[]")
    logger.debug { "monsters loaded from resource = ${monsters.size}" }

    // each arg should be a json file (spells, monsters, character, or attacks) or a debug cmd (dump, search, test)
    for (i in args.indices) {
        val arg = args[i]
        if (arg.startsWith("+feat")) {
            val split = arg.split("=")
            character!!.addFeat(com.vikinghelmet.dnd.dpr.character.feats.Feat.valueOf(split[1]))
        }
        else if (arg.startsWith("+")) {
            val split = arg.substringAfter("+").split("=")
            val ability = com.vikinghelmet.dnd.dpr.character.stats.AbilityType.fromShortName(split[0]) ?: throw IllegalArgumentException("unknown ability: "+split[0])
            character!!.updateAbilityScore(ability, split[1].toInt())
        }
        else if (arg.startsWith("--maxTurns")) {
            Constants.NUM_TURNS_PER_SCENARIO = arg.split("=")[1].toInt()
        }
        else if (arg.startsWith("--maxResults")) {
            Constants.SCENARIO_OUTPUT_MAX = arg.split("=")[1].toInt()
        }
        else if (arg.startsWith("-")) {
            when (arg) {
                "-i" -> { Globals.initLogger(LogLevel.INFO) }
                "-d" -> { Globals.initLogger(LogLevel.DEBUG) }

                "--csv" -> AttackResultFormatter.isCSV = true;
                "-a" -> {
                    val monster = Globals.getMonster(args[i+1])

                    for (turn in args[i+2].split(";")) {
                        val attackList = mutableListOf<Attack>()
                        for (attackName in turn.split(",")) {
                            try {
                                attackList.add (Attack (monster, character!!.getWeapon(attackName)))
                            }
                            catch (e: Exception) {
                                val spell = Globals.getSpell(attackName, character!!.is2014())
                                logger.debug { "spell = ${spell.fullString()}" }
                                attackList.add (Attack (monster, Globals.getSpell(attackName, character!!.is2014())))
                            }
                        }
                        turns.add(Turn(attackList))
                    }

                    break
                }
                "-z" -> {
                    exitEarly = true
                    showResults(runScenarios(character!!, args, i))
                }
                "-p" -> {
                    exitEarly = true
                    val level = args[i+1].toInt()
                    val resultList: MutableList<ScenarioResult> = mutableListOf()

                    dprFiles.getEditableCharacterList().forEach { name ->
                        val c = dprFiles.getEditableCharacter(name)
                        c!!.editableFields.level = level
                        resultList.addAll(runScenarios(c!!, args, i+1))
                    }

                    showResults(resultList)
                }
                else -> println("invalid argument: $arg")
            }
        }
        else if (arg.endsWith(".json") || arg.contains("/")) {
            val jsonString = getFileOrURL(arg)
            if (jsonString == null) {
                println("unable to read input: $arg")
            }
            else if (jsonString.contains("School")) {
                spells.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"Monsters\"")){
                monsters.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"remoteId\"")) {
                character = getEditableCharacter(jsonString)
                logger.debug { "# loaded editable character: $character" }
            }
            else if (jsonString.contains("\"username\"")) {
                character = Json.decodeFromString(jsonString)
            }
            else if (jsonString.contains("\"Always prepared spells successfully received.\"")) {
                val alwaysPrepared: AlwaysPreparedSpells = Json.decodeFromString(jsonString)
                val names = alwaysPrepared.data.map { it.definition.name }
                logger.info { "# alwaysPrepared: ${ names }" }
            }
            else {
                println("# unsupported json file: $arg")
                exitEarly = true
            }
        }
        else if (arg.endsWith(".json")){
            println("unknown file type: $arg")
        }
        else if (arg.startsWith("character") || arg.startsWith("https://www.dndbeyond.com/characters")) {
            var remoteId: String? = CharacterAPI.getCharacterId(arg)
            if (remoteId != null) {
                character = getCharacter(remoteId)
            }
        }
        else if (arg.startsWith("dump")) {
            Globals.dump(arg, character, turns)
            exitEarly = true
        }
        else if (arg.startsWith("search")) {
            Globals.search(arg)
            exitEarly = true
        }
        else if (arg.startsWith("test:character")) {
            println(character!!.toStringAll())
            exitEarly = true
        }
        else if (arg.startsWith("test:subclass")) {
            val result = Globals.getSubclassSpellsPrepared(arg.substringAfterLast(':'))
            result.forEach { println("level = ${it.level}, spells = ${it.spells}") }
            exitEarly = true
        }
        else if (arg.startsWith("test:plan")) {
            val editableCharacter = dprFiles.getEditableCharacter(args[i+1])
            println("plan = ${editableCharacter!!.editableFields.toPrettyPlan() }")
            AbilityType.entries.forEach {
                println("ability = $it, score = ${editableCharacter.getModifiedAbilityScore(it)}")
            }
            exitEarly = true
        }
        else if (arg.startsWith("test:available")) {
            ScenarioBuilder(character!!, Globals.getMonster("Goblin")).testActionsAvailable()
            exitEarly = true
        }
        else if (arg.startsWith("test:turnOptions")) {
            val builder =ScenarioBuilder(character!!, Globals.getMonster("Goblin"))
            builder.build(args[i+1].toInt(), args[i+2].toInt(), DEFAULT_NUM_TARGETS, DEFAULT_TARGET_RADIUS)

            builder.turnOptions.forEach {
                val buf = StringBuilder()
                it.attacks.forEach { buf.append(it.getLabel()).append(",") }
                println("turn option = { $buf }")
            }
            //println("turnOptions = ${ builder.turnOptions }")

            exitEarly = true
        }
        else if (arg.startsWith("test:spells")) {
//            character!!.getPreparedSpells().forEach { spell ->
//                println("alwaysPrepared = ${spell.alwaysPrepared}, spell = ${spell.name}")
//            }
            character!!.getAlwaysPreparedSpells().forEach { spell ->
                println("alwaysPrepared2 = ${spell.alwaysPrepared}, spell = ${spell.definition.name}")
            }
        }
        else if (arg.startsWith("test:build")) {
            val builder = ScenarioBuilder(character!!, Globals.getMonster("Goblin"))
            builder.build(args[i+1].toInt(), args[i+2].toInt(), DEFAULT_NUM_TARGETS, DEFAULT_TARGET_RADIUS).forEach {
                println("scenario = ${it.getLabel()}")
            }
            exitEarly = true
        }
        else if (arg.startsWith("test:file:write")) {
            dprFiles.write("this is a test", "example.txt")
            exitEarly = true
        }
        else if (arg.startsWith("test:file:read")) {
            val result = dprFiles.read("example.txt")
            println("read result = $result")
            exitEarly = true
        }
        else if (arg.startsWith("test:csvUp")) {
            val csvContent = dprFiles.readAttackCSV()
            println("attack csv size = ${ csvContent?.length ?: 0 }")
            if (csvContent != null) {
                val props = getProperties("secret.properties")
                val csvUploadUrl = props["csvUploadUrl"]
                println("csvUploadUrl = $csvUploadUrl")

                if (csvUploadUrl != null && csvUploadUrl is String) runBlocking {
                    var csvDownloadUrl = CharacterAPI.postRequest(csvUploadUrl,csvContent)
                    println("csvDownloadUrl = $csvDownloadUrl")

                    val fetch = CharacterAPI.getRequest(csvDownloadUrl)
                    println("csvDownload, fetched data size= ${fetch.length}")
                }
            }
            //LocalUriHandler
            exitEarly = true
        }
    }

    if (exitEarly) {
    }
    else if (spells.isEmpty()) {
        println("no spell data")
    }
    else if (monsters.isEmpty()) {
        println("no monsters data")
    }
    else if (character == null) {
        println("no character data")
    }
    else if (turns.isNotEmpty()) {
        val attackNames = turns.map { it.attacks.map { it.action.toString() }}
        logger.debug { "attackNames = $attackNames" }

        val scenario = Scenario(character, turns, DEFAULT_NUM_TARGETS, DEFAULT_TARGET_RADIUS)
        val scenarioResult = ScenarioCalculator(scenario).calculateDPRForAllTurns()
        logger.debug { "scenario = ${ scenarioResult.attackResults }" }
        println (scenarioResult.output())
    }

    CharacterAPI.closeHttpClient() // don't forget to do this, otherwise the program may run forever
}
